private void tdCredit_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       // --- Declare values ---
decimal stained = 0;
decimal adheringShaving = 0;
decimal dirtyEgg = 0;
decimal sampleQty = 0;

// --- Read values ---
if (GetCurrentColumnValue("Stained") != null)
    stained = Convert.ToDecimal(GetCurrentColumnValue("Stained"));

if (GetCurrentColumnValue("AdheringShaving") != null)
    adheringShaving = Convert.ToDecimal(GetCurrentColumnValue("AdheringShaving"));

if (GetCurrentColumnValue("DirtyEgg") != null)
    dirtyEgg = Convert.ToDecimal(GetCurrentColumnValue("DirtyEgg"));

if (GetCurrentColumnValue("SampleQty") != null)
    sampleQty = Convert.ToDecimal(GetCurrentColumnValue("SampleQty"));

// --- Equation ---
decimal percentage = 0;
decimal totalSpecialRow = stained + adheringShaving + dirtyEgg;
if (sampleQty > 0)
    percentage = ((stained + adheringShaving + dirtyEgg) * 100m) / sampleQty;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = percentage.ToString("0.##"); // format with up to 2 decimals
// --- Weighted totals ---
TotalSpecialEggs += totalSpecialRow;
TotalSpecialEggsSampleQty += sampleQty;
}

